import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"HavenBot — investor playbook","description":"Phrasing that works for buy, claim, rebalance, set policy, pause.","frontmatter":{"title":"HavenBot — investor playbook","description":"Phrasing that works for buy, claim, rebalance, set policy, pause."},"headers":[],"relativePath":"havenbot/investor-playbook.md","filePath":"havenbot/investor-playbook.md","lastUpdated":1780245214000}'),i={name:"havenbot/investor-playbook.md"};function d(n,t,s,l,h,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="investor-playbook" tabindex="-1">Investor playbook <a class="header-anchor" href="#investor-playbook" aria-label="Permalink to &quot;Investor playbook&quot;">​</a></h1><p>A working glossary of phrases that HavenBot reliably maps to the right tool. The LLM is good at intent — but a clean phrase saves a round-trip and avoids ambiguity.</p><p>Every row below follows the same shape: <strong>what you say</strong> → <strong>what the agent calls</strong> → <strong>what you confirm</strong>. Pick a row, copy the phrase, paste into the agent chat — done.</p><blockquote><p>Throughout this page, <code>&lt;TOKEN&gt;</code> stands in for any active RWA token in your catalog. Replace it with the actual symbol you&#39;re working with (the token tile on the dashboard&#39;s Tokens page shows the exact spelling).</p></blockquote><h2 id="portfolio-inspection" tabindex="-1">Portfolio inspection <a class="header-anchor" href="#portfolio-inspection" aria-label="Permalink to &quot;Portfolio inspection&quot;">​</a></h2><p>These are read-only — no signing, no confirmation.</p><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Current holdings overview</td><td>&quot;Show my portfolio.&quot;</td></tr><tr><td>Specific token balance</td><td>&quot;What&#39;s my <code>&lt;TOKEN&gt;</code> balance?&quot; <em>(triggers <code>muhaven_unseal_position</code>)</em></td></tr><tr><td>Yield earned this epoch</td><td>&quot;How much did <code>&lt;TOKEN&gt;</code> pay last epoch?&quot;</td></tr><tr><td>Yield earned over a window</td><td>&quot;Show <code>&lt;TOKEN&gt;</code> yields for the past 30 days.&quot;</td></tr><tr><td>Token NAV</td><td>&quot;What&#39;s the current NAV of <code>&lt;TOKEN&gt;</code>?&quot;</td></tr><tr><td>Compare token NAVs</td><td>&quot;Which active RWA token has the highest NAV right now?&quot;</td></tr><tr><td>Audit log</td><td>&quot;What did my agent do today?&quot;</td></tr><tr><td>Risk-signal flags</td><td>&quot;Am I overexposed?&quot; <em>(reads <code>ebool isOverexposed</code>)</em></td></tr><tr><td>Pending yield across all tokens</td><td>&quot;What yield is claimable across all my positions?&quot;</td></tr></tbody></table><h2 id="buying" tabindex="-1">Buying <a class="header-anchor" href="#buying" aria-label="Permalink to &quot;Buying&quot;">​</a></h2><p>Every buy opens ConfirmModal. The cleartext preview shows amount, estimated shares, NAV, and slippage — you decide whether to sign.</p><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Buy a fixed amount</td><td>&quot;Buy 100 mhUSDC of <code>&lt;TOKEN&gt;</code>.&quot;</td></tr><tr><td>Buy at a target share count</td><td>&quot;Buy ~50 <code>&lt;TOKEN&gt;</code> shares.&quot; <em>(HavenBot computes the mhUSDC needed at current NAV)</em></td></tr><tr><td>Quote before buying</td><td>&quot;Quote 100 mhUSDC of <code>&lt;TOKEN&gt;</code>.&quot;</td></tr><tr><td>Buy a percent of cash</td><td>&quot;Put 20% of my mhUSDC into <code>&lt;TOKEN&gt;</code>.&quot;</td></tr><tr><td>Buy with a NAV ceiling</td><td>&quot;Buy 100 mhUSDC of <code>&lt;TOKEN&gt;</code> only if NAV is below 1.005.&quot;</td></tr></tbody></table><h2 id="claiming-yield" tabindex="-1">Claiming yield <a class="header-anchor" href="#claiming-yield" aria-label="Permalink to &quot;Claiming yield&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Claim a finalized epoch</td><td>&quot;Claim my <code>&lt;TOKEN&gt;</code> yield for epoch 5.&quot;</td></tr><tr><td>Claim everything available</td><td>&quot;Claim all my pending yield.&quot;</td></tr><tr><td>Check what&#39;s claimable</td><td>&quot;What yield can I claim right now?&quot;</td></tr><tr><td>Claim and summarize after</td><td>&quot;Claim all my pending yield, then show me the new portfolio totals.&quot;</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Yield is per-investor in MuHaven</p><p>Each finalized epoch creates a personal <code>MuHavenEscrow</code> for every eligible holder. Your claim pulls only your share — the operator never knows your individual amount.</p></div><h2 id="set-policy-tier" tabindex="-1">Set policy / tier <a class="header-anchor" href="#set-policy-tier" aria-label="Permalink to &quot;Set policy / tier&quot;">​</a></h2><p>Tier changes are signed by your passkey (not the session key) — see <a href="/policy/tiered-autonomy">Tiered autonomy</a>.</p><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Switch tier</td><td>&quot;Switch me to Confirm-per-action.&quot; or &quot;Arm Scoped autonomy.&quot;</td></tr><tr><td>Inspect current tier</td><td>&quot;What tier am I in?&quot;</td></tr><tr><td>See my session-key scope</td><td>&quot;Show my session-key permissions.&quot;</td></tr><tr><td>Set a per-trade cap (Scoped autonomy)</td><td>&quot;Arm Scoped autonomy with a $500 per-trade cap.&quot;</td></tr><tr><td>Set a max drawdown</td><td>&quot;Don&#39;t let me lose more than 10% in a single position.&quot; <em>(Policy-bound — designed; the risk engine isn&#39;t running today)</em></td></tr><tr><td>Re-authorize the session key</td><td>&quot;Renew my session key for another hour.&quot;</td></tr></tbody></table><h2 id="the-pause-kill-switch" tabindex="-1">The /pause kill-switch <a class="header-anchor" href="#the-pause-kill-switch" aria-label="Permalink to &quot;The /pause kill-switch&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Stop the agent immediately</td><td>&quot;Pause my agent.&quot;</td></tr><tr><td>Verify pause status</td><td>&quot;Is my agent paused?&quot;</td></tr><tr><td>Resume</td><td>&quot;Resume my agent.&quot;</td></tr></tbody></table><p>Pause is <strong>idempotent</strong>: calling it twice doesn&#39;t error. It uninstalls the on-chain session-key validator in ≤1 Arb block. Subsequent propose calls return <code>423 PAUSED</code>.</p><p>Resume mints a fresh session key — your passkey signs the validator-install. See <a href="/policy/pause">The /pause kill-switch</a>.</p><h2 id="audit-inspection" tabindex="-1">Audit &amp; inspection <a class="header-anchor" href="#audit-inspection" aria-label="Permalink to &quot;Audit &amp; inspection&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Recent audit</td><td>&quot;Show my agent&#39;s audit log.&quot;</td></tr><tr><td>Filter by tool</td><td>&quot;Show audit rows for <code>propose_buy</code> in the last 7 days.&quot;</td></tr><tr><td>Filter by outcome</td><td>&quot;Show only failed agent actions.&quot;</td></tr><tr><td>Filter by surface</td><td>&quot;Show audit rows that came from MCP this week.&quot;</td></tr><tr><td>Export</td><td>&quot;Export my audit log.&quot; <em>(returns a downloadable JSON)</em></td></tr></tbody></table><p>The audit log is your forensic record. See <a href="/policy/audit-log">Audit log</a> for what&#39;s logged vs. what&#39;s intentionally not.</p><h2 id="what-havenbot-won-t-do" tabindex="-1">What HavenBot won&#39;t do <a class="header-anchor" href="#what-havenbot-won-t-do" aria-label="Permalink to &quot;What HavenBot won&#39;t do&quot;">​</a></h2><ul><li><strong>It won&#39;t give financial advice.</strong> Ask &quot;should I buy <code>&lt;TOKEN&gt;</code>?&quot; and HavenBot will give you the NAV, the recent yield history, the protection-pool state — not &quot;yes, buy it.&quot;</li><li><strong>It won&#39;t move funds out of your MuHaven wallet.</strong> The session-key scope is locked to MuHaven contracts. There is no <code>transfer-to-external-EOA</code> tool.</li><li><strong>It won&#39;t bypass your tier.</strong> Asking &quot;buy $50K of <code>&lt;TOKEN&gt;</code>&quot; while in Advisory tier triggers a passkey prompt; while running under a Scoped autonomy session with a $5K per-trade cap, it&#39;s rejected by the on-chain validator (not silently downgraded to $5K).</li><li><strong>It won&#39;t act in another user&#39;s account.</strong> Cross-user audit access and encrypted-vote retrieval require permits the other user must sign.</li></ul><h2 id="common-mistakes" tabindex="-1">Common mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common mistakes&quot;">​</a></h2><ul><li><strong>&quot;Buy <code>&lt;TOKEN&gt;</code>&quot;</strong> without an amount → HavenBot will ask you to clarify the amount in mhUSDC or shares.</li><li><strong>&quot;Sell my <code>&lt;TOKEN&gt;</code> position&quot;</strong> while you have zero of that token → the policy gate rejects the propose with <code>BalanceTooLow</code> <em>after</em> showing you a zero-amount preview (silent-fail privacy property).</li><li><strong>&quot;Set my risk to high&quot;</strong> → too vague. Use concrete params: &quot;Cap my daily spend at $500&quot;, &quot;Allow up to 20% drawdown on <code>&lt;TOKEN&gt;</code>&quot;.</li><li><strong>&quot;Pause my MCP and HavenBot but not Telegram&quot;</strong> → <code>/pause</code> is <strong>global</strong>. It uninstalls the on-chain validator; there&#39;s no per-surface pause. To pause one surface, deauthorize that surface specifically (e.g., <code>muhaven-broker logout</code> for MCP).</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/havenbot/issuer-playbook">Issuer playbook</a> — the issuer-side phrasing.</li><li><a href="/havenbot/troubleshooting">Troubleshooting</a> — what to do when things go wrong.</li><li><a href="/reference/tool-catalog">Tool catalog</a> — the full schema for every tool.</li></ul>',29)])])}const y=e(i,[["render",d]]);export{p as __pageData,y as default};
